#!/bin/bash
# SubagentStop hook: Auto-saves session data to agent memory.
# Generated by buddyx-forge.

PROJECT_DIR="$(git rev-parse --show-toplevel 2>/dev/null || pwd)"
TODAY=$(date +%Y-%m-%d)

INPUT=$(cat)
if ! command -v jq &>/dev/null; then
  exit 0
fi
AGENT_TYPE=$(echo "$INPUT" | jq -r '.agent_type // empty' 2>/dev/null)
AGENT_TYPE=$(echo "$AGENT_TYPE" | tr -cd 'a-zA-Z0-9-')

if ! echo "$AGENT_TYPE" | grep -q "^webapp-"; then
  exit 0
fi

MEMORY_DIR="${PROJECT_DIR}/.claude/agent-memory/${AGENT_TYPE}"
MEMORY_FILE="${MEMORY_DIR}/MEMORY.md"

mkdir -p "$MEMORY_DIR" 2>/dev/null || exit 0

if [ ! -f "$MEMORY_FILE" ]; then
  cat > "$MEMORY_FILE" <<MEOF
# ${AGENT_TYPE} Memory

> Learnings from past sessions. Read before starting, write after completing.

## Session Log

## File Patterns

## Bug Patterns

## Performance Notes

## Code Conventions

## Cross-Agent Notes
MEOF
fi

CHANGED_FILES=$(git -C "$PROJECT_DIR" diff --name-only 2>/dev/null | head -10)
CHANGED_COUNT=$(echo "$CHANGED_FILES" | grep -c "." 2>/dev/null || echo "0")

if [ "$CHANGED_COUNT" -gt 0 ]; then
  {
    echo ""
    echo "### [${TODAY}] Session"
    echo "- Agent: ${AGENT_TYPE}"
    echo "- Files changed: ${CHANGED_COUNT}"
    echo "$CHANGED_FILES" | head -5 | while read -r f; do
      [ -n "$f" ] && echo "  - ${f}"
    done
  } >> "$MEMORY_FILE"
fi

# Rotation: keep under 180 lines
LINE_COUNT=$(wc -l < "$MEMORY_FILE" 2>/dev/null || echo "0")
if [ "$LINE_COUNT" -gt 180 ]; then
  head -20 "$MEMORY_FILE" > "${MEMORY_FILE}.tmp"
  tail -150 "$MEMORY_FILE" >> "${MEMORY_FILE}.tmp"
  mv "${MEMORY_FILE}.tmp" "$MEMORY_FILE"
fi

exit 0
